,'reporting_rtc_ggr','SUCCESS 878','success','model',6.057278156280518,'2026-04-09T21:00:54.077193Z','2026-04-09T21:00:59.968823Z','2026-04-09T21:00:54.037281Z','2026-04-09T21:00:54.076592Z',878,False,'with casino_ggr as (\n    select\n        --acco_id,\n        settled_date_alk,\n        sum(ggr) as ggr\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG\n    where is_test_account = 0\n    group by all\n)\n\nselect\n    *,\n    sysdate() as UpdateTimeUTC\nfrom casino_ggr',NULL,'01c399ec-0212-644a-24dd-0703192fa493','Thread-11 (worker)','table','{"_message": "SUCCESS 878", "code": "SUCCESS", "rows_affected": 878, "query_id": "01c399ec-0212-644a-24dd-0703192fa493", "rows_inserted": 878, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.rtc_top_up_campaigns','model.dbt_casino.rtc_top_up_campaigns','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
  current_timestamp::timestamp
,'rtc_top_up_campaigns','SUCCESS 91568','success','model',102.16613459587097,'2026-04-09T21:00:54.389416Z','2026-04-09T21:02:36.099116Z','2026-04-09T21:00:54.043050Z','2026-04-09T21:00:54.383593Z',91568,False,'WITH\nrtc_top_up_campaigns AS\n(\n\nSELECT\n\n    to_timestamp(timestamp)::date as date,\n    ca.user_id,\n    ca.campaign_name,\n    ca.message_type,\n    interaction_type,\n    \nFROM \nFBG_SOURCE.XTREMEPUSH.CAMPAIGNS as ca\nWHERE (LOWER(campaign_name) ILIKE \'%vip casino rtc top up%\' OR lower(campaign_name) ILIKE \'%vip rtc top up%\')\n    and category_name = \'Casino Marketing \'\n    and to_timestamp(timestamp)::date > \'2025-03-01\'\n    and message_type IN (\'journey\')\n    and interaction_type = \'sent\'\n    \n),\nbonus_winnings_last30\nAS\n(\n\nSELECT\n    acco_id,\n    SUM(CASE WHEN cpl.transaction in (\'bonus winnings\', \'fancash jackpot contribution\') THEN cpl.amount ELSE 0 END) AS bonus_winnings\n\nFROM\nFBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger as cpl\nWHERE cpl.day between cpl.day - 29 and cpl.day\ngroup by all \n\n),\n\nggr_last_30\nAS\n(\n\nSELECT\n    c.acco_id,\n    sum(c.ggr) as ggr,\n    sum(c.ngr) as ngr\n\nFROM\nFBG_ANALYTICS_ENGINEERING.CASINO.casino_daily_settled_agg c\nWHERE\nc.settled_date_alk BETWEEN c.settled_date_alk - 29 and c.settled_date_alk AND c.is_test_account = 0 and c.total_void = 0\ngroup by all \n\n)\n\nSELECT \n\nrtc.*,\ncm.acco_id,\ncm.vip_host,\nCASE WHEN recommended_casino_bonus_reason = \'RTC Top Up\' THEN RECOMMENDED_CASINO_BONUS_AWARDED_AMOUNT ELSE 0 END as RECOMMENDED_CASINO_BONUS_AWARDED_AMOUNT,\ncm.coded_cas_tier,\ncm.current_casino_segment_tier,\nbl.bonus_winnings,\ngl.ggr,\ngl.ngr\n\nFROM \nrtc_top_up_campaigns rtc\nleft join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart cm on (rtc.user_id = cm.amelco_id)\nleft join bonus_winnings_last30 bl ON (cm.acco_id = bl.acco_id)\nleft join ggr_last_30 gl on (cm.acco_id = gl.acco_id)\nleft join FBG_ANALYTICS.CASINO.crm_casino_bonus_model cbm on (cbm.acco_id = gl.acco_id)\nWHERE cm.is_test_account = FALSE\nGROUP BY ALL',NULL,'01c399ec-0212-6cb9-24dd-0703192f8563','Thread-13 (worker)','table','{"_message": "SUCCESS 91568", "code": "SUCCESS", "rows_affected": 91568, "query_id": "01c399ec-0212-6cb9-24dd-0703192f8563", "rows_inserted": 91568, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.dummy_optin','model.dbt_casino.dummy_optin','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
  current_timestamp::timestamp
,'dummy_optin','SUCCESS 20153832','success','model',138.13073444366455,'2026-04-09T21:00:54.957536Z','2026-04-09T21:03:12.048316Z','2026-04-09T21:00:54.019723Z','2026-04-09T21:00:54.942625Z',20153832,False,'with bonus_campaign_opt_ins as (\n    select distinct\n        acco_id,\n        bonus_campaign_id,\n        convert_timezone(\'UTC\', \'America/New_York\',\n            to_timestamp_ntz(try_to_number(split_part(split_part(overrides, \'optInTime=\', 2), \';\', 1)), 3)) as optintime_ET,\n    case when state <> \'AVAILABLE\' then acco_id else null end as opt_in\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    where (modified >= dateadd(\'day\', -21, current_date())\n           and overrides like \'%optInTime%\')\n    or bonus_campaign_id in (\'87819\')\n),\n\nbonus_campaign_details as (\n    select  \n        id,\n        convert_timezone(\'UTC\',\'America/New_York\',to_timestamp(parse_json(data):Bonus:starts::string)) as bonus_start_date_ET,\n        convert_timezone(\'UTC\',\'America/New_York\',to_timestamp(parse_json(data):Bonus:expires::string)) as bonus_end_date_ET\n    from FBG_SOURCE.OSB_SOURCE.BONUS_CAMPAIGNS\n    where bonus_start_date_ET >= dateadd(\'day\', -21, current_date())\n    or id IN (\'87819\')\n),\n\nfancash_amount as (\n    select \n        bet_id,\n        sum(fancash_amount) as fancash_amount\n    from FBG_SOURCE.FANX_MONGODB.FANCASH\n    where ledger_entry_reason = \'CASINO_BETTING\'\n    group by all\n),\n\nfancash_amount_forgone_into_jackpots as (\n    select\n        bet_id,\n        sum(amount) as fancash_amount_forgone\n    from FBG_ANALYTICS.CASINO.fc_jackpots_awarded_stg\n    where transaction = \'bonus awarded\'\n    group by all\n),\n\ncasino_transactions as (\n    select\n        acco_id,\n        bet_id,\n        placed_time_est,\n        game_id,\n        stake,\n        payout\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART\n    where void = 0\n    and fund_type_id = 1\n)\n\nselect\n    oi.acco_id,\n    cs.is_test_account,\n    cs.vip_host as "Account Manager",\n    oi.bonus_campaign_id,\n    cs.amelco_id,\n    oi.optintime_ET,\n    cg.game_name,\n    cs.current_state as jurisdiction_name,\n    d.bonus_start_date_ET,\n    d.bonus_end_date_ET,\n    count(distinct opt_in) as opt_ins,\n    sum(cba.stake) as cash_stake,\n    sum(cba.payout) as cash_payout,\n    sum(case when cg.game_type = \'SLOT\' then cba.stake else 0 end) as slot_cash_stake,\n    sum(case when cg.game_type = \'SLOT\' then cba.payout else 0 end) as slot_cash_payout,\n    sum(case when cg.game_type = \'TABLE\' then cba.stake else 0 end) as table_cash_stake,\n    sum(case when cg.game_type = \'TABLE\' then cba.payout else 0 end) as table_cash_payout,\n    sum(fancash_amount) as fc_accrued,\n    coalesce(sum(fancash_amount),0) + coalesce(sum(fancash_amount_forgone),0) as fc_theo_accrued,\n    sysdate() as UpdateTimeUTC\nfrom bonus_campaign_opt_ins oi\nleft join bonus_campaign_details d on oi.bonus_campaign_id = d.id \nleft join casino_transactions cba on cba.acco_id = oi.acco_id and cba.placed_time_est between d.bonus_start_date_ET and d.bonus_end_date_ET\nleft join FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_GAME_DETAILS cg on cg.game_id = cba.game_id\ninner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART cs on cs.acco_id = oi.acco_id\nleft join fancash_amount fc on cba.bet_id = fc.bet_id\nleft join fancash_amount_forgone_into_jackpots fcj on cba.bet_id = fcj.bet_id\ngroup by all',NULL,'01c399ec-0212-67a9-24dd-0703192f94ff','Thread-7 (worker)','table','{"_message": "SUCCESS 20153832", "code": "SUCCESS", "rows_affected": 20153832, "query_id": "01c399ec-0212-67a9-24dd-0703192f94ff", "rows_inserted": 20153832, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.dummy_optin_based_on_optin','model.dbt_casino.dummy_optin_based_on_optin','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
