,'dummy_optin_based_on_optin','SUCCESS 16983993','success','model',170.27487063407898,'2026-04-09T21:00:54.955634Z','2026-04-09T21:03:44.175086Z','2026-04-09T21:00:54.024936Z','2026-04-09T21:00:54.677185Z',16983993,False,'with bonus_campaign_opt_ins as (\n    select distinct\n        acco_id,\n        bonus_campaign_id,\n        convert_timezone(\'UTC\', \'America/New_York\',\n            to_timestamp_ntz(try_to_number(split_part(split_part(overrides, \'optInTime=\', 2), \';\', 1)), 3)) as optintime_ET,\n    case when state <> \'AVAILABLE\' then acco_id else null end as opt_in\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    where (modified >= dateadd(\'day\', -21, current_date()) \n           and overrides like \'%optInTime%\')\n    or bonus_campaign_id in (\'80442\', \'80443\')\n),\n\nbonus_campaign_details as (\n    select  \n        id,\n        convert_timezone(\'UTC\',\'America/New_York\',to_timestamp(parse_json(data):Bonus:starts::string)) as bonus_start_date_ET,\n        convert_timezone(\'UTC\',\'America/New_York\',to_timestamp(parse_json(data):Bonus:expires::string)) as bonus_end_date_ET\n    from FBG_SOURCE.OSB_SOURCE.BONUS_CAMPAIGNS\n    where bonus_start_date_ET >= dateadd(\'day\', -21, current_date())\n    or id in (\'80442\', \'80443\')\n),\n\nfancash_amount as (\n    select \n        bet_id,\n        sum(fancash_amount) as fancash_amount\n    from FBG_SOURCE.FANX_MONGODB.FANCASH\n    where ledger_entry_reason = \'CASINO_BETTING\'\n    group by all\n),\n\nfancash_amount_forgone_into_jackpots as (\n    select\n        bet_id,\n        sum(amount) as fancash_amount_forgone\n    from FBG_ANALYTICS.CASINO.fc_jackpots_awarded_stg\n    where transaction = \'bonus awarded\'\n    group by all\n),\n\ncasino_transactions as (\n    select\n        acco_id,\n        bet_id,\n        placed_time_est,\n        game_id,\n        stake,\n        payout\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART\n    where void = 0\n    and fund_type_id = 1\n)\n\nselect\n    oi.acco_id,\n    cs.is_test_account,\n    cs.vip_host as "Account Manager",\n    oi.bonus_campaign_id,\n    cs.amelco_id,\n    oi.optintime_ET,\n    cg.game_name,\n    cs.current_state as jurisdiction_name,\n    d.bonus_start_date_ET,\n    d.bonus_end_date_ET,\n    count(distinct opt_in) as opt_ins,\n    sum(cba.stake) as cash_stake,\n    sum(cba.payout) as cash_payout,\n    sum(case when cg.game_type = \'SLOT\' then cba.stake else 0 end) as slot_cash_stake,\n    sum(case when cg.game_type = \'SLOT\' then cba.payout else 0 end) as slot_cash_payout,\n    sum(case when cg.game_type = \'TABLE\' then cba.stake else 0 end) as table_cash_stake,\n    sum(case when cg.game_type = \'TABLE\' then cba.payout else 0 end) as table_cash_payout,\n    sum(fancash_amount) as fc_accrued,\n    coalesce(sum(fancash_amount),0) + coalesce(sum(fancash_amount_forgone),0) as fc_theo_accrued,\n    sysdate() as UpdateTimeUTC\nfrom bonus_campaign_opt_ins oi\nleft join bonus_campaign_details d on oi.bonus_campaign_id = d.id\nleft join casino_transactions cba on cba.acco_id = oi.acco_id and cba.placed_time_est between oi.optintime_ET and d.bonus_end_date_ET\nleft join FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_GAME_DETAILS cg on cg.game_id = cba.game_id\ninner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART cs on cs.acco_id = oi.acco_id\nleft join fancash_amount fc on cba.bet_id = fc.bet_id\nleft join fancash_amount_forgone_into_jackpots fcj on cba.bet_id = fcj.bet_id\ngroup by all',NULL,'01c399ec-0212-67a8-24dd-0703192f6d7b','Thread-8 (worker)','table','{"_message": "SUCCESS 16983993", "code": "SUCCESS", "rows_affected": 16983993, "query_id": "01c399ec-0212-67a8-24dd-0703192f6d7b", "rows_inserted": 16983993, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.f2p_segments','model.dbt_casino.f2p_segments','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
  current_timestamp::timestamp
,'f2p_segments','SUCCESS 984971','success','model',176.599613904953,'2026-04-09T21:00:55.223959Z','2026-04-09T21:03:50.460661Z','2026-04-09T21:00:54.029736Z','2026-04-09T21:00:54.950365Z',984971,False,'with backbone as ( --noqa: disable=all\n    select\n        s.acco_id,\n        s.is_casino_vip,\n        date(sysdate()) as calendar_date,\n        datediff(\'day\', date(ftu.ftu_date_ak), date(sysdate())) as casino_tenure,\n        case when datediff(\'day\', date(ftu.ftu_date_ak), date(sysdate())) <= 7 then 1 else 0 end new_customer_flag\n    from FBG_ANALYTICS_ENGINEERING.STAGING.STG_ACCOUNT_STATUS s\n    inner join FBG_ANALYTICS_ENGINEERING.STAGING.STG_CASINO_FIRST_TIME_USER ftu\n    on s.acco_id = ftu.acco_id \n    where (s.is_test_account = 0 \n        or s.acco_id in (4566530, 5356076, 4213612, 1482827, 950998, 5405441, 4281556)) -- hardcode allow specific test accounts for testing purposes\n),\n\n/* 20260220 - Request for some VIPs to be put straight into Low Ace Tier for 45 days */\nmanual_vip_override as (\n    select\n        a.acco_id,\n        date(max(campaign_start_date)) as edit_tier_start_date,\n        date(dateadd(day, 44, max(campaign_start_date))) as edit_tier_end_date,\n        1 as vip_override\n    from fbg_analytics.vip.project_250_campaigns a\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b on a.acco_id = b.acco_id\n    where date(campaign_start_date) >= \'2026-02-19\'\n    and date(sysdate()) between date(campaign_start_date) and date(dateadd(day, 44, campaign_start_date))\n    and b.is_test_account = 0\n    group by all\n),\n\nbackbone_inc_vip_override as (\n    select\n        coalesce(a.acco_id, b.acco_id) as acco_id,\n        coalesce(a.is_casino_vip, 1) as is_casino_vip,\n        coalesce(a.calendar_date, date(sysdate())) as calendar_date,\n        coalesce(a.casino_tenure, 0) as casino_tenure,\n        coalesce(a.new_customer_flag, 0) as new_customer_flag,\n        coalesce(b.vip_override,0) as vip_override\n    from backbone a\n    full join manual_vip_override b on a.acco_id = b.acco_id\n),\n\nsegments as (\n    select \n        bb.acco_id,\n        bb.calendar_date as date, \n        bb.is_casino_vip,\n        casino_tenure,\n        new_customer_flag,\n        cs.casino_tier,\n        cs.l90d_scaled_engr,\n        cs.l90d_scaled_ngr,\n        nvl(days_active_multiplier,1) as multiplier,\n        sum(cb.ngr) as l90d_ngr,\n        sum(cb.expected_ngr) as l90d_engr,\n        sum(case when cb.settled_date_alk between bb.calendar_date - 27 and bb.calendar_date then cb.ngr else 0 end) l28d_ngr,\n        sum(case when cb.settled_date_alk between bb.calendar_date - 27 and bb.calendar_date then cb.expected_ngr else 0 end) l28d_engr,\n        0.3*l90d_ngr + 0.7*l90d_engr as l90d_bngr,\n        0.3*l28d_ngr + 0.7*l28d_engr as l28d_bngr,      \n        case\n            when bb.acco_id in (4566530, 5356076, 4213612, 1482827, 950998, 5405441, 4281556) then \'Promo Abuser - 5x\'\n            when greatest(l90d_bngr, l90d_engr) >= 65000 / multiplier then \'Top Ace\'\n            when greatest(l90d_bngr, l90d_engr) >= 25000 / multiplier then \'High Ace\'\n            when bb.vip_override = 1 then \'Low Ace\'\n            when greatest(l90d_bngr, l90d_engr) >= 11000 / multiplier then \'Low Ace\'\n            when greatest(l90d_bngr, l90d_engr) >= 6500 / multiplier then \'High King\'\n            when greatest(l90d_bngr, l90d_engr) >= 2500 / multiplier then \'Low King\'\n\n            when l90d_engr <= -50 and new_customer_flag <> 1 and bb.is_casino_vip = 0 then \'Persistent Promo Abuser\'\n            when ((l90d_bngr > 0 and l28d_bngr < 0) \n                or l90d_bngr < 0 \n                or any_value(casino_illegitimate_intent) = TRUE \n                or any_value(f2p_illegitimate_intent) = TRUE\n                or any_value(is_opposite_betting) = TRUE\n                or any_value(is_devicesharing_illegitimate_intent) = TRUE\n                or any_value(raf_illegitimate_intent) = TRUE\n                or any_value(cs.casino_tier) in (0,2)) then \'Persistent Promo Abuser\'     \n            when new_customer_flag = 1 then \'Low King\'\n            when greatest(l90d_bngr, l90d_engr) >= 2250 / multiplier and l28d_bngr < 0 then \'Queen\'\n            when l90d_bngr >= 550 / multiplier and l28d_bngr >= 0 then \'Queen\'\n            when l90d_bngr >= 550 / multiplier and l28d_bngr < 0 then \'Jack\'\n            when l90d_bngr >= 30 / multiplier and l28d_bngr >= 0 then \'Jack\'\n            when l90d_bngr >= 30 / multiplier and l28d_bngr < 0 then \'Deuce\'\n            when l90d_bngr >= 0 and l28d_bngr >= 0 then \'Deuce\'\n            else \'Unassigned\' \n        end as casino_segment\n    from backbone_inc_vip_override bb\n    left join FBG_ANALYTICS.CASINO.casino_illegitimate_intent cii\n    on bb.acco_id = cii.acco_id\n    left join FBG_ANALYTICS.CASINO.f2p_illegitimate_intent fii\n    on bb.acco_id = fii.acco_id\n    left join FBG_ANALYTICS.CASINO.opposite_betting_illegitimate_intent obii\n    on bb.acco_id = obii.acco_id\n    left join FBG_ANALYTICS.CASINO.devicesharing_illegitimate_intent dsii\n    on bb.acco_id = dsii.acco_id\n    left join FBG_ANALYTICS.CASINO.raf_illegitimate_intent rii\n    on bb.acco_id = rii.referral_acco_id\n    left join FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG cb\n    on bb.acco_id = cb.acco_id and cb.settled_date_alk between bb.calendar_date - 89 and bb.calendar_date\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CASINO_MULTIPLIER  cm\n    on bb.casino_tenure = cm.days_old_oc\n    left join FBG_ANALYTICS.CASINO.casino_segments cs\n    on bb.acco_id = cs.acco_id\n    group by\n        bb.acco_id,\n        bb.calendar_date,\n        bb.is_casino_vip,\n        bb.vip_override,\n        casino_tenure,\n        new_customer_flag,\n        cs.casino_tier,\n        cs.l90d_scaled_engr,\n        cs.l90d_scaled_ngr,\n        multiplier\n)\n\nselect \n    acco_id,\n    date,\n    casino_segment\nfrom segments',NULL,'01c399ec-0212-6b00-24dd-0703192f7813','Thread-9 (worker)','table','{"_message": "SUCCESS 984971", "code": "SUCCESS", "rows_affected": 984971, "query_id": "01c399ec-0212-6b00-24dd-0703192f7813", "rows_inserted": 984971, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.filtered_cash_game_summary','model.dbt_casino.filtered_cash_game_summary','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
  current_timestamp::timestamp
,'filtered_cash_game_summary','SUCCESS 9067','success','model',340.82048058509827,'2026-04-09T21:00:54.398183Z','2026-04-09T21:06:34.698195Z','2026-04-09T21:00:54.034201Z','2026-04-09T21:00:54.393284Z',9067,False,'WITH filtered_cash_handle_and_users AS (--noqa: disable=all --test\n    SELECT \n        g.game_name,\n        g.game_id,\n        g.global_game_id as external_game_id,\n        g.is_live_dealer,\n        g.game_provider,\n        g.support_jackpots,\n        g.game_type,\n        g.granular_game_type,\n        g.tagline,\n        g.category,\n        g.min_bet,\n        r.status,\n        a.state,\n        a.acco_id,\n        a.settled_date_alk,\n        SUM(freespin_bet_stake + casino_credit_bet_stake) AS bonus_handle,\n        SUM(CASE \n                WHEN freespin_bet_stake + casino_credit_bet_stake >= 0.01 * cash_bet_stake\n                THEN 0 ELSE cash_bet_stake \n            END) AS filtered_cash_handle,\n        COUNT(DISTINCT CASE \n                WHEN freespin_bet_stake + casino_credit_bet_stake >= 0.01 * cash_bet_stake\n                THEN NULL ELSE a.acco_id \n            END) AS filtered_cash_users\n    FROM FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG a\n    LEFT JOIN FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_GAME_DETAILS g\n        ON a.game_id = g.game_id \n    LEFT JOIN FBG_SOURCE.OSB_SOURCE.RGS_GAMES r\n        ON a.game_id = r.id\n    WHERE g.is_live_dealer = \'FALSE\'\n        AND a.is_test_account = 0\n        AND r.status = \'LIVE\'\n    GROUP BY ALL\n),\n\naggregated_cash_handle_and_users AS (\n    SELECT \n        game_name,\n        game_id,\n        external_game_id,\n        is_live_dealer,\n        game_provider,\n        support_jackpots,\n        game_type,\n        granular_game_type,\n        category,\n        status,\n        tagline,\n        min_bet,\n        state,\n        acco_id,\n        SUM(CASE  \n                WHEN settled_date_alk >= DATEADD(DAY, -1, CURRENT_DATE) \n                THEN filtered_cash_handle  \n                ELSE 0 END) AS filtered_cash_handle_last_1_day,      \n        SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -7, CURRENT_DATE) \n                THEN filtered_cash_handle \n                ELSE 0 END) AS filtered_cash_handle_last_7_days,\n        SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -14, CURRENT_DATE) \n                THEN filtered_cash_handle \n                ELSE 0 END) AS filtered_cash_handle_last_14_days,\n        SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -28, CURRENT_DATE) \n                AND settled_date_alk < CURRENT_DATE \n                THEN filtered_cash_handle \n                ELSE 0 END) AS filtered_cash_handle_last_28_days,\n        SUM(CASE  \n                WHEN settled_date_alk >= DATEADD(DAY, -1, CURRENT_DATE)\n                THEN filtered_cash_users  \n                ELSE 0 END) AS filtered_cash_users_last_1_day,      \n        SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -7, CURRENT_DATE) \n                AND settled_date_alk < CURRENT_DATE \n                THEN filtered_cash_users \n                ELSE 0 END) AS filtered_cash_users_last_7_days,\n         SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -14, CURRENT_DATE) \n                AND settled_date_alk < CURRENT_DATE \n                THEN filtered_cash_users \n                ELSE 0 END) AS filtered_cash_users_last_14_days,        \n        SUM(CASE \n                WHEN settled_date_alk >= DATEADD(DAY, -28, CURRENT_DATE) \n                AND settled_date_alk < CURRENT_DATE \n                THEN filtered_cash_users \n                ELSE 0 END) AS filtered_cash_users_last_28_days\n    FROM filtered_cash_handle_and_users\n    GROUP BY ALL\n),\n\ngame_total_cash_handle AS (\n    SELECT \n        game_name,\n        SUM(filtered_cash_handle_last_1_day) AS total_cash_handle_last_1_day,\n        SUM(filtered_cash_handle_last_7_days) AS total_cash_handle_last_7_days,\n        SUM(filtered_cash_handle_last_14_days) AS total_cash_handle_last_14_days,\n        SUM(filtered_cash_handle_last_28_days) AS total_cash_handle_last_28_days\n    FROM aggregated_cash_handle_and_users\n    GROUP BY game_name\n),\n\nfiltered_cash_game_summary AS (\n    SELECT \n        a.game_name,\n        a.game_id,\n        a.external_game_id,\n        a.category,\n        a.status,\n        a.is_live_dealer,\n        a.game_provider,\n        a.support_jackpots,\n        a.game_type,\n        a.granular_game_type,\n        a.tagline,\n        a.state,\n        a.min_bet,\n        \n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_1_day > 0.25 * g.total_cash_handle_last_1_day \n            THEN 0 ELSE a.filtered_cash_handle_last_1_day \n        END) AS adjusted_cash_handle_last_1_day,\n        \n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_7_days > 0.25 * g.total_cash_handle_last_7_days \n            THEN 0 ELSE a.filtered_cash_handle_last_7_days \n        END) AS adjusted_cash_handle_last_7_days,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_14_days > 0.25 * g.total_cash_handle_last_14_days \n            THEN 0 ELSE a.filtered_cash_handle_last_14_days \n        END) AS adjusted_cash_handle_last_14_days,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_28_days > 0.25 * g.total_cash_handle_last_28_days \n            THEN 0 ELSE a.filtered_cash_handle_last_28_days \n        END) AS adjusted_cash_handle_last_28_days,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_1_day > 0.25 * g.total_cash_handle_last_1_day \n            THEN 0 ELSE a.filtered_cash_users_last_1_day \n        END) AS adjusted_cash_users_last_1_day,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_7_days > 0.25 * g.total_cash_handle_last_7_days \n            THEN 0 ELSE a.filtered_cash_users_last_7_days \n        END) AS adjusted_cash_users_last_7_days,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_14_days > 0.25 * g.total_cash_handle_last_14_days \n            THEN 0 ELSE a.filtered_cash_users_last_14_days \n        END) AS adjusted_cash_users_last_14_days,\n\n        SUM(CASE \n            WHEN a.filtered_cash_handle_last_28_days > 0.25 * g.total_cash_handle_last_28_days \n            THEN 0 ELSE a.filtered_cash_users_last_28_days \n        END) AS adjusted_cash_users_last_28_days\n\n    FROM aggregated_cash_handle_and_users a\n    LEFT JOIN game_total_cash_handle g\n        ON a.game_name = g.game_name\n    GROUP BY \n       a.game_name, a.game_id, a.is_live_dealer, a.game_provider, \n        a.support_jackpots, a.game_type, a.granular_game_type, \n        a.tagline, a.state, a.external_game_id, a.category,a.status,a.min_bet\n)\n\nSELECT * FROM filtered_cash_game_summary',NULL,'01c399ec-0212-6e7d-24dd-0703192fb47b','Thread-10 (worker)','table','{"_message": "SUCCESS 9067", "code": "SUCCESS", "rows_affected": 9067, "query_id": "01c399ec-0212-6e7d-24dd-0703192fb47b", "rows_inserted": 9067, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.casino_business_performance_report','model.dbt_casino.casino_business_performance_report','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
  current_timestamp::timestamp
,'casino_business_performance_report','SUCCESS 62375704','success','model',493.8610990047455,'2026-04-09T21:00:56.134095Z','2026-04-09T21:09:07.757412Z','2026-04-09T21:00:54.005341Z','2026-04-09T21:00:56.128023Z',62375704,False,'with users as (\n    select \n        acco_id,\n        date(casino_ftcu_date_alk) FTCU_date,\n        date(casino_ftu_date_alk) FTU_date,\n        first_product,\n        case when acquisition_channel like \'PB%\' then \'PointsBet\' else acquisition_channel end acq_source,\n        is_casino_vip current_casino_vip\n    from FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART\n    where (casino_ftu_date_alk is not null or acco_id in (select distinct acco_id from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS))\n        and is_test_account = 0\n),\n\nactives as (\n    select \n    distinct \n    acco_id, \n    trunc(SK_Date, \'month\') SK_Month,\n    trunc(SK_Date, \'week\') SK_Week,\n    SK_Date\n    from (\n    \n        select \n            acco_id,\n            cast(convert_timezone(\'UTC\', \'America/Anchorage\', trans_date) as date) SK_Date               \n        from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n\n        union all\n\n        select\n            ats_account_id as acco_id,\n            date(convert_timezone(\'UTC\', \'America/Anchorage\', settled_on)) SK_Date\n        from FBG_SOURCE.FANX_MONGODB.FANCASH\n\n        union all\n\n        select\n            acco_id,\n            day SK_Date\n        from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger\n\n        union all\n\n        select\n            acco_id,\n            date(convert_timezone(\'UTC\', \'America/Anchorage\', time_awarded)) SK_Date\n        from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS\n\n        union all\n\n        select\n            customer_id as acco_id,\n            bus_date SK_Date\n        from FBG_FINANCE.FINANCE_MART.DAILY_CUSTOMER_REV\n    )\n),\n\nwager_jurisdictions as (\n    select \n        acco_id,\n        jurisdictions_code as jurisdiction,\n        placed_date_alk start_date,\n        coalesce(lead(placed_date_alk, 1) over (partition by acco_id order by placed_date_alk) - 1, \'2099-01-01\') end_date\n    from (\n        select \n            acco_id, \n            jurisdictions_code, \n            date(placed_time_alk) placed_date_alk, \n            row_number() over (partition by acco_id, date(placed_time_alk) order by placed_time_alk desc) rk\n        from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART\n        where test = 0\n        qualify rk = 1\n    )\n),\n\nplatform as (\n    with platform_time_range as (\n        select \n            user_id as acco_id, \n            coalesce(product, \'Sportsbook App\') as platform,\n            start_time_alk, \n            lead(start_time_alk,1) over (partition by user_id order by start_time_alk) end_time_alk\n        from (\n            select user_id, product, convert_timezone(\'UTC\',\'America/Anchorage\',login_time_utc) as start_time_alk\n            from FBG_ANALYTICS.PRODUCT.USER_LOGIN_BY_PRODUCT\n            union all\n            select user_id, product, convert_timezone(\'UTC\',\'America/Anchorage\',reg_start_time_utc) as start_time_alk\n            from FBG_ANALYTICS.PRODUCT.USER_REG_BY_PRODUCT\n        )\n    )\n    \n    select \n        date(start_time_alk) start_date_alk,\n        coalesce(date(end_time_alk) - 1,\'2099-01-01\') end_date_alk,\n        platform, \n        acco_id\n    from platform_time_range\n    where (date(start_time_alk) < date(end_time_alk) or end_time_alk is null)\n    group by all\n),\n\ncasino_vip_history as (\n    select \n        start_date,\n        end_date,\n        acco_id,\n        greatest(casino_vip,vip) as casino_vip\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.customer_account_history\n), \n\nfancash_jackpots as (\n    with fc_jp_opt_ins as (\n    select \n        acco_id,\n        convert_timezone(\'UTC\',\'America/Anchorage\',change_timestamp) as change_timestamp_alk,\n        lead(change_timestamp_alk,1) over (partition by acco_id order by change_timestamp asc) as next_change_timestamp_alk,\n        is_opted_in as fancash_jackpot_opt_in_status,\n        contribution_percentage as fancash_jackpot_contribution_percentage\n    from FBG_SOURCE.OSB_SOURCE.FANCASH_JACKPOT_OPTIN_HISTORY\n    where ext_jackpot_group_id = \'h2hDbKqN\'\n    )\n\n    select \n        acco_id,\n        date(change_timestamp_alk) as start_date_alk,\n        coalesce(date(next_change_timestamp_alk)-1, \'2099-01-01\') as end_date_alk,\n        fancash_jackpot_opt_in_status,\n        fancash_jackpot_contribution_percentage\n    from fc_jp_opt_ins\n    where start_date_alk < end_date_alk or end_date_alk is null\n),\n\nsegments as (\n    select \n        u.acco_id,\n        FTCU_date,\n        FTU_date,\n        acq_source,\n        first_product,\n        current_casino_vip,\n        a.SK_Month,\n        a.SK_Week,\n        a.SK_Date,\n        nvl(cvh.casino_vip,0) casino_vip,\n        nvl(cvh2.casino_vip,0) casino_vip_som,\n        cl.casino_cluster,\n        vs.casino_tier,      \n        vs.casino_value,\n        vs.casino_super_vip,\n        wj.jurisdiction,\n        coalesce(p.platform, \'Sportsbook App\') platform,\n        coalesce(fcjp.fancash_jackpot_opt_in_status,FALSE) fancash_jackpot_opt_in_status,\n        nvl(fcjp.fancash_jackpot_contribution_percentage,0) fancash_jackpot_contribution_percentage,\n        pp.product_preference_365 as product_preference,\n        coalesce(cc.segment, \'None\') core_cluster,\n        coalesce(f1.loyalty_tier, \'None\') f1_loyalty_tier,\n        wlc.CasinoLifecycle as week_lifecycle,                \n        mlc.CasinoLifecycle as month_lifecycle, \n        fs.forecast_segment,\n        coalesce(bj.blackjack_segment, \'Unknown\') blackjack_segment\n    from users u\n    inner join actives a \n    on u.acco_id = a.acco_id\n    left join FBG_ANALYTICS.CASINO.casino_behavioural_clusters_historical cl\n    on a.SK_date between cl.start_date and cl.end_date and u.acco_id = cl.acco_id\n    left join FBG_ANALYTICS.CASINO.casino_segments_historical vs\n    on a.SK_date = vs.date and u.acco_id = vs.acco_id\n    left join casino_vip_history cvh\n    on a.SK_date between cvh.start_date and cvh.end_date and u.acco_id = cvh.acco_id\n    left join casino_vip_history cvh2\n    on date_trunc(\'month\',a.SK_date) between cvh2.start_date and cvh2.end_date and u.acco_id = cvh2.acco_id\n    left join wager_jurisdictions wj\n    on u.acco_id = wj.acco_id and a.sk_date between wj.start_date and wj.end_date\n    left join platform p\n    on u.acco_id = p.acco_id and a.sk_date between p.start_date_alk and p.end_date_alk\n    left join fancash_jackpots fcjp\n    on u.acco_id = fcjp.acco_id and a.sk_date between fcjp.start_date_alk and fcjp.end_date_alk\n    left join FBG_ANALYTICS.CASINO.product_preference_historical pp\n    on a.SK_date between pp.start_date and pp.end_date and u.acco_id = pp.acco_id\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.F1_ATTRIBUTES_AUDITS f1\n    on a.SK_date = f1.as_of_date and u.acco_id = f1.acco_id\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CASINO_SEGMENTATION  cc\n    on a.SK_date = cc.last_updated_date and u.acco_id = cc.acco_id\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CALENDAR_WEEK_GLOBAL_LIFECYCLE wlc\n    on u.acco_id = wlc.acco_id and a.SK_Week = wlc.SK_Week\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CALENDAR_MONTH_GLOBAL_LIFECYCLE mlc\n    on u.acco_id = mlc.acco_id and a.SK_Month = mlc.SK_Month\n    left join FBG_ANALYTICS.CASINO.casino_forecast_segments fs\n    on u.acco_id = fs.acco_id and a.sk_month = fs.month_start_date\n    left join FBG_ANALYTICS.CASINO.boom_blackjack_strategy_segments bj\n    on u.acco_id = bj.user_id\n    \n),\n\nCasinoActivity as (\n    select\n        acco_id, \n        settled_date_alk SK_Date,\n        count(distinct case when cash_bet_stake > 0 then settled_date_alk end) as APDs,\n        count(distinct case when total_stake > 0 then settled_date_alk end) as PDs,\n        sum(cash_bet_count) as bet_count, \n        sum(cash_bet_stake) as cash_handle,\n        sum(total_stake) as total_handle,\n        sum(ggr) as cash_GGR,    \n        sum(ngr) as trading_NGR,\n        sum(expected_ggr) as cash_eGGR,\n        sum(expected_ngr) as trading_eNGR,\n        sum(cash_bet_stake - cash_bet_payout) as cash_pnl,\n        \n        sum(case when gd.game_type = \'SLOT\' and gd.is_live_dealer = FALSE then cash_bet_stake else 0 end) slot_handle,\n        sum(case when gd.game_type = \'TABLE\' and gd.is_live_dealer = FALSE then cash_bet_stake else 0 end) table_handle,\n        sum(case when gd.is_live_dealer = TRUE then cash_bet_stake else 0 end) live_handle,\n        sum(case when gd.game_type = \'SLOT\' and gd.is_live_dealer = FALSE then ggr else 0 end) slot_ggr,\n        sum(case when gd.game_type = \'TABLE\' and gd.is_live_dealer = FALSE then ggr else 0 end) table_ggr,\n        sum(case when gd.is_live_dealer = TRUE then ggr else 0 end) live_ggr,\n        \n        sum(case when dsa.platform = \'Sportsbook App\' then cash_bet_stake else 0 end) sportsbook_app_handle,\n        sum(case when dsa.platform in (\'Casino Android App\', \'Casino iOS App\') then cash_bet_stake else 0 end) casino_app_handle,\n        sum(case when dsa.platform_id = \'610715\' then cash_bet_stake else 0 end) web_app_handle,\n        sum(case when dsa.platform = \'Sportsbook App\' then ggr else 0 end) sportsbook_app_ggr,\n        sum(case when dsa.platform in (\'Casino Android App\', \'Casino iOS App\') then ggr else 0 end) casino_app_ggr,\n        sum(case when dsa.platform_id = \'610715\' then ggr else 0 end) web_app_ggr,\n        \n        sum(total_jackpot_contribution) jackpot_contributions\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG dsa\n    inner join FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_GAME_DETAILS gd\n    on dsa.game_id = gd.game_id\n    group by 1,2\n),\n\njackpots as (\nselect \n    acco_id, \n    date(convert_timezone(\'UTC\',\'America/Anchorage\', transaction_time)) sk_date, \n    sum(win_amount) as jackpot_winnings\nfrom FBG_SOURCE.OSB_SOURCE.JACKPOT_TRANSACTIONS\nwhere transaction_type = \'WIN\'\ngroup by 1,2\n),\n\nDeposits as (\n    select\n        acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', created)) SK_Date,\n        count(distinct created) Deposit_Count,\n        sum(nvl(Amount,0)) Deposit_Amount \n    from FBG_SOURCE.OSB_SOURCE.DEPOSITS d\n    left join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS j \n    on j.id = d.jurisdictions_id\n    where status = \'DEPOSIT_SUCCESS\'\n        and deleted = 0\n    group by 1,2\n),\n\nWithdrawals as (\n    select \n        account_id acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', initiated_at)) SK_Date,\n        count(distinct initiated_at) Withdrawal_Count,\n        sum(nvl(Amount,0)) Withdrawal_Amount\n    from FBG_SOURCE.OSB_SOURCE.WITHDRAWALS w\n    left join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS j \n    on j.id = w.jurisdictions_id\n    where status = \'WITHDRAWAL_COMPLETED\'\n        and deleted = 0\n    group by 1,2\n),\n\nfinance_revenue as (\n    select \n        customer_id as acco_id,\n        bus_date as sk_date, \n        sum(priced_ggr) as finance_priced_ggr,\n        sum(priced_ngr) as finance_priced_ngr,\n        sum(nominal_ggr) as finance_nominal_ggr,\n        sum(nominal_ngr) as finance_nominal_ngr\n    from FBG_FINANCE.FINANCE_MART.DAILY_CUSTOMER_REV a\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b on a.customer_id = b.acco_id and b.is_test_account = 0\n    where a.subledger_application = \'iCasino\'\n    group by all\n),\n\nf2p_activity as (\n    select\n        acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', time_awarded)) sk_date,\n        count(distinct time_awarded) f2p_sessions,\n        count(distinct case when pp.casino_segment like \'%Premium\' then time_awarded end) f2p_supercharged_sessions\n    from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS gsr\n    inner join FBG_SOURCE.OSB_SOURCE.F2P_PRIZE_POOL pp\n    on gsr.prize_pool_id = pp.id\n    group by 1,2\n), \n\nOCPromoLedgerAwards as (\n    select\n        acco_id,\n        day as sk_date,\n        sum(nvl(amount,0)) as bonus_awarded,\n        sum(case when coalesce("Bonus Category", \'Retention\') like \'%Acquisition\' then amount else 0 end) acq_bonus_awarded,\n        sum(case when coalesce("Bonus Category", \'Retention\') not like \'%Acquisition\' then amount else 0 end) ret_bonus_awarded,\n        sum(case when promo_type = \'free_spin\' then amount else 0 end) fs_awarded,\n        sum(case when promo_type like \'fancash%\' then amount else 0 end) fc_awarded,\n        sum(case when promo_type = \'cash_back\' then amount else 0 end) cb_awarded,\n        sum(case when promo_type = \'casino_credit\' then amount else 0 end) cc_awarded,\n        sum(case when "Series" = \'Spin to Win\' then amount else 0 end) f2p_awarded,\n        sum(case when promo_type = \'bonus_bet\' then amount else 0 end) bb_awarded,\n        sum(case when promo_type = \'fanatics_one_credit\' then amount else 0 end) f1c_awarded\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger\n    where transaction = \'bonus awarded\'\n    group by all\n)\n\n, OCPromoLedgerCosts as (\n    select\n        acco_id,\n        day as sk_date,\n        sum(nvl(amount,0)) as bonus_costs,\n        sum(case when coalesce("Bonus Category", \'Retention\') like \'%Acquisition\' then amount else 0 end) acq_bonus_costs,\n        sum(case when coalesce("Bonus Category", \'Retention\') not like \'%Acquisition\' then amount else 0 end) ret_bonus_costs,\n        sum(case when promo_type = \'free_spin\' then amount else 0 end) fs_costs,\n        sum(case when promo_type like \'fancash%\' then amount else 0 end) fc_costs,\n        sum(case when promo_type = \'cash_back\' then amount else 0 end) cb_costs,\n        sum(case when promo_type = \'casino_credit\' then amount else 0 end) cc_costs,\n        sum(case when "Series" = \'Spin to Win\' then amount else 0 end) f2p_costs,\n        sum(case when promo_type = \'bonus_bet\' then amount else 0 end) bb_costs,\n        sum(case when promo_type = \'fanatics_one_credit\' then amount else 0 end) f1c_costs\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger\n    where transaction in (\'bonus winnings\', \'fancash jackpot contribution\')\n    group by all\n),\n\nOCPromoLedgerExpectedCosts as (\n    select\n        acco_id,\n        day as sk_date,\n        sum(nvl(amount,0)) as bonus_exp_costs,\n        sum(case when coalesce("Bonus Category", \'Retention\') like \'%Acquisition\' then amount else 0 end) acq_bonus_exp_costs,\n        sum(case when coalesce("Bonus Category", \'Retention\') not like \'%Acquisition\' then amount else 0 end) ret_bonus_exp_costs,\n        sum(case when promo_type = \'free_spin\' then amount else 0 end) fs_exp_costs,\n        sum(case when promo_type like \'fancash%\' then amount else 0 end) fc_exp_costs,\n        sum(case when promo_type = \'cash_back\' then amount else 0 end) cb_exp_costs,\n        sum(case when promo_type = \'casino_credit\' then amount else 0 end) cc_exp_costs,\n        sum(case when "Series" = \'Spin to Win\' then amount else 0 end) f2p_exp_costs,\n        sum(case when promo_type = \'bonus_bet\' then amount else 0 end) bb_exp_costs,\n        sum(case when promo_type = \'fanatics_one_credit\' then amount else 0 end) f1c_exp_costs\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger\n    where transaction in (\'bonus expected winnings\', \'fancash jackpot contribution\')\n    group by all\n),\n\nCasino_LTV as (\n    select \n        acco_id,\n        pred_gp_18mo_oc_final f18m_pgp\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.ACQUISITION_CUSTOMER_MART\n    where pred_gp_18mo_oc_final is not null\n),\n\nCVP_GGR_Ratios as (\n    select \n        date_trunc(\'month\',date) as sk_month,\n        acco_id,\n        div0(sum(nvl(oc_eggr,0)),sum(nvl(oc_eggr,0)+nvl(osb_eggr,0))) eggr_ratio\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CUSTOMER_VARIABLE_PROFIT\n    group by 1,2\n),\n\nCOGS as (\n    select \n        cvp.acco_id, \n        date as sk_date,\n        sum(nvl(oc_tax,0)) as tax,\n        sum(nvl(icasino_content,0)) as content_fees,\n        sum(nvl(market_access_fee,0)* nvl(eggr_ratio,0)) as market_access_fees,\n        sum(nvl(payment_fees,0)* nvl(eggr_ratio,0)) as payment_fees,\n        sum(nvl(gc_rate,0)* nvl(eggr_ratio,0)) as geolocation_fees\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CUSTOMER_VARIABLE_PROFIT cvp\n    left join CVP_GGR_Ratios cvpg\n    on date_trunc(\'month\',cvp.date) = cvpg.sk_month and cvp.acco_id = cvpg.acco_id\n    group by 1,2\n),\n\n        \nAccountData as (\n      select \n        s.acco_id,\n        s.FTCU_date,\n        s.FTU_date,\n        s.acq_source,\n        s.first_product,\n        s.current_casino_vip,\n        s.SK_Month,\n        s.SK_Week,\n        s.SK_Date,\n        s.casino_vip,\n        s.casino_vip_som,\n        s.casino_tier,\n        s.casino_value,\n        s.casino_super_vip,\n        s.casino_cluster,\n        s.jurisdiction,\n        s.platform,\n        s.fancash_jackpot_opt_in_status,\n        s.fancash_jackpot_contribution_percentage,\n        s.product_preference,\n        s.core_cluster,\n        s.f1_loyalty_tier,\n        s.week_lifecycle,                \n        s.month_lifecycle,    \n        s.forecast_segment,    \n        s.blackjack_segment,        \n    \n        nvl(APDs,0) APDs,\n        nvl(PDs,0) PDs,\n        nvl(bet_count,0) bet_count,\n        nvl(cash_handle,0) cash_handle,\n        nvl(cash_ggr,0) cash_ggr,\n        nvl(Trading_NGR,0) Trading_NGR,\n        nvl(cash_ggr,0) - nvl(bonus_costs,0) commercial_NGR,\n        nvl(cash_eggr,0) - nvl(bonus_exp_costs,0) commercial_eNGR,\n        nvl(cash_pnl,0) cash_pnl,\n        \n        nvl(cash_eggr,0) cash_eggr,\n        nvl(Trading_eNGR,0) Trading_eNGR,\n\n        nvl(slot_handle,0) slot_handle,\n        nvl(table_handle,0) table_handle,\n        nvl(live_handle,0) live_handle,\n        nvl(slot_ggr,0) slot_ggr,\n        nvl(table_ggr,0) table_ggr,\n        nvl(live_ggr,0) live_ggr,\n\n        nvl(sportsbook_app_handle,0) sportsbook_app_handle,\n        nvl(casino_app_handle,0) casino_app_handle,\n        nvl(web_app_handle,0) web_app_handle,\n        nvl(sportsbook_app_ggr,0) sportsbook_app_ggr,\n        nvl(casino_app_ggr,0) casino_app_ggr,\n        nvl(web_app_ggr,0) web_app_ggr,\n    \n        \n        nvl(jackpot_contributions,0) jackpot_contributions,\n        nvl(jackpot_winnings,0) jackpot_winnings,\n\n        nvl(finance_priced_ggr,0) finance_priced_ggr,\n        nvl(finance_priced_ngr,0) finance_priced_ngr,\n        nvl(finance_nominal_ggr,0) finance_nominal_ggr,\n        nvl(finance_nominal_ngr,0) finance_nominal_ngr,\n        \n        nvl(f2p_sessions,0) f2p_sessions,\n        nvl(f2p_supercharged_sessions,0) f2p_supercharged_sessions,\n\n        nvl(bonus_awarded,0) bonus_awarded,\n        nvl(acq_bonus_awarded,0) acq_bonus_awarded,\n        nvl(ret_bonus_awarded,0) ret_bonus_awarded,\n        nvl(fs_awarded,0) fs_awarded,\n        nvl(fc_awarded,0) fc_awarded,\n        nvl(cb_awarded,0) cb_awarded,\n        nvl(cc_awarded,0) cc_awarded,\n        nvl(f2p_awarded,0) f2p_awarded,\n        nvl(bb_awarded,0) bb_awarded,\n        nvl(f1c_awarded,0) f1c_awarded,\n\n        nvl(bonus_costs,0) bonus_costs,\n        nvl(acq_bonus_costs,0) acq_bonus_costs,\n        nvl(ret_bonus_costs,0) ret_bonus_costs,\n        nvl(fs_costs,0) fs_costs,\n        nvl(fc_costs,0) fc_costs,\n        nvl(cb_costs,0) cb_costs,\n        nvl(cc_costs,0) cc_costs,\n        nvl(f2p_costs,0) f2p_costs,\n        nvl(bb_costs,0) bb_costs,\n        nvl(f1c_costs,0) f1c_costs,\n\n        nvl(bonus_exp_costs,0) bonus_exp_costs,\n        nvl(acq_bonus_exp_costs,0) acq_bonus_exp_costs,\n        nvl(ret_bonus_exp_costs,0) ret_bonus_exp_costs,\n        nvl(fs_exp_costs,0) fs_exp_costs,\n        nvl(fc_exp_costs,0) fc_exp_costs,\n        nvl(cb_exp_costs,0) cb_exp_costs,\n        nvl(cc_exp_costs,0) cc_exp_costs,\n        nvl(f2p_exp_costs,0) f2p_exp_costs,\n        nvl(bb_exp_costs,0) bb_exp_costs,\n        nvl(f1c_exp_costs,0) f1c_exp_costs,\n    \n        nvl(Deposit_Amount,0) Deposit_Amount,\n        nvl(Withdrawal_Amount,0) Withdrawal_Amount,\n        nvl(deposit_count,0) deposit_count,\n        nvl(Withdrawal_count,0) Withdrawal_count,\n\n        nvl(f18m_pgp,0) f18m_pgp,\n\n        nvl(tax,0) tax,\n        nvl(content_fees,0) content_fees,\n        nvl(market_access_fees,0) market_access_fees,\n        nvl(payment_fees,0) payment_fees,\n        nvl(geolocation_fees,0) geolocation_fees\n\n    from segments s\n    left join CasinoActivity ca\n    on s.acco_id = ca.acco_id and s.SK_Date = ca.SK_Date\n    left join Jackpots jp\n    on s.acco_id = jp.acco_id and s.SK_Date = jp.SK_Date\n    left join Deposits d\n    on s.acco_id = d.acco_id and s.SK_Date = d.SK_Date\n    left join Withdrawals w\n    on s.acco_id = w.acco_id and s.SK_Date = w.SK_Date\n    left join finance_revenue fr\n    on s.acco_id = fr.acco_id and s.SK_Date = fr.SK_Date\n    left join f2p_activity f2p\n    on s.acco_id = f2p.acco_id and s.SK_Date = f2p.SK_Date\n    left join OCPromoLedgerAwards cpla\n    on s.acco_id = cpla.acco_id and s.SK_Date = cpla.SK_Date\n    left join OCPromoLedgerCosts cplc\n    on s.acco_id = cplc.acco_id and s.SK_Date = cplc.SK_Date\n    left join OCPromoLedgerExpectedCosts cple\n    on s.acco_id = cple.acco_id and s.SK_Date = cple.SK_Date\n    left join Casino_LTV ltv\n    on s.acco_id = ltv.acco_id\n    left join COGS f\n    on s.acco_id = f.acco_id and s.sk_date = f.sk_date\n)\n\nselect distinct\n    ad.acco_id,\n    ad.FTCU_date,\n    ad.FTU_date,\n    ad.acq_source,\n    ad.first_product,\n    ad.current_casino_vip,\n    ad.SK_Month,\n    ad.SK_Week,\n    ad.SK_Date,\n    ad.casino_vip,\n    ad.casino_vip_som,\n    ad.casino_tier,\n    ad.casino_value,\n    ad.casino_super_vip,\n    ad.jurisdiction,\n    ad.platform,\n    ad.fancash_jackpot_opt_in_status,\n    ad.fancash_jackpot_contribution_percentage,\n    ad.casino_cluster,\n    ad.product_preference,\n    ad.core_cluster,\n    ad.f1_loyalty_tier,\n    ad.week_lifecycle, \n    ad.month_lifecycle, \n    ad.forecast_segment,\n    ad.blackjack_segment,\n                    \n    cast(ad.APDs as int) APDs,\n    cast(ad.PDs as int) PDs,\n    ad.bet_count bet_count,\n    cast(ad.cash_handle as decimal(11,2)) cash_handle,\n    cast(ad.cash_GGR as decimal(11,2)) cash_GGR,\n    cast(ad.Trading_NGR as decimal(11,2)) Trading_NGR,\n    cast(ad.commercial_NGR as decimal(11,2)) commercial_NGR,\n    cast(ad.commercial_eNGR as decimal(11,2)) commercial_eNGR,\n    cast(ad.cash_pnl as decimal(11,2)) cash_pnl,\n    cast(ad.cash_eGGR as decimal(11,2)) cash_eGGR,\n    cast(ad.Trading_eNGR as decimal(11,2)) Trading_eNGR,\n\n    cast(ad.slot_handle as decimal(11,2)) slot_handle,\n    cast(ad.table_handle as decimal(11,2)) table_handle,\n    cast(ad.live_handle as decimal(11,2)) live_handle,\n    cast(ad.slot_ggr as decimal(11,2)) slot_ggr,\n    cast(ad.table_ggr as decimal(11,2)) table_ggr,\n    cast(ad.live_ggr as decimal(11,2)) live_ggr,\n\n    cast(ad.sportsbook_app_handle as decimal(11,2)) sportsbook_app_handle,\n    cast(ad.casino_app_handle as decimal(11,2)) casino_app_handle,\n    cast(ad.web_app_handle as decimal(11,2)) web_app_handle,\n    cast(ad.sportsbook_app_ggr as decimal(11,2)) sportsbook_app_ggr,\n    cast(ad.casino_app_ggr as decimal(11,2)) casino_app_ggr,\n    cast(ad.web_app_ggr as decimal(11,2)) web_app_ggr,\n\n    cast(ad.jackpot_contributions as decimal(11,2)) jackpot_contributions,\n    cast(ad.jackpot_winnings as decimal(11,2)) jackpot_winnings,\n\n    cast(finance_priced_ggr as decimal(11,2)) as finance_priced_ggr,\n    cast(finance_priced_ngr as decimal(11,2)) as finance_priced_ngr,\n    cast(finance_nominal_ggr as decimal(11,2)) as finance_nominal_ggr,\n    cast(finance_nominal_ngr as decimal(11,2)) as finance_nominal_ngr,\n    \n    cast(f2p_sessions as int) f2p_sessions,\n    cast(f2p_supercharged_sessions as int) f2p_supercharged_sessions,\n    \n    cast(ad.bonus_awarded as decimal(11,2)) bonus_awarded,\n    cast(ad.acq_bonus_awarded as decimal(11,2)) acq_bonus_awarded,\n    cast(ad.ret_bonus_awarded as decimal(11,2)) ret_bonus_awarded,\n    cast(ad.fs_awarded as decimal(11,2)) fs_awarded,\n    cast(ad.fc_awarded as decimal(11,2)) fc_awarded,\n    cast(ad.cb_awarded as decimal(11,2)) cb_awarded,\n    cast(ad.cc_awarded as decimal(11,2)) cc_awarded,\n    cast(ad.f2p_awarded as decimal(11,2)) f2p_awarded,\n    cast(ad.bb_awarded as decimal(11,2)) bb_awarded,\n    cast(ad.f1c_awarded as decimal(11,2)) f1c_awarded,\n    \n    cast(ad.bonus_costs as decimal(11,2)) bonus_costs,\n    cast(ad.acq_bonus_costs as decimal(11,2)) acq_bonus_costs,\n    cast(ad.ret_bonus_costs as decimal(11,2)) ret_bonus_costs,\n    cast(ad.fs_costs as decimal(11,2)) fs_costs,\n    cast(ad.fc_costs as decimal(11,2)) fc_costs,\n    cast(ad.cb_costs as decimal(11,2)) cb_costs,\n    cast(ad.cc_costs as decimal(11,2)) cc_costs,\n    cast(ad.f2p_costs as decimal(11,2)) f2p_costs,\n    cast(ad.bb_costs as decimal(11,2)) bb_costs,\n    cast(ad.f1c_costs as decimal(11,2)) f1c_costs,\n\n    cast(ad.bonus_exp_costs as decimal(11,2)) bonus_exp_costs,\n    cast(ad.acq_bonus_exp_costs as decimal(11,2)) acq_bonus_exp_costs,\n    cast(ad.ret_bonus_exp_costs as decimal(11,2)) ret_bonus_exp_costs,\n    cast(ad.fs_exp_costs as decimal(11,2)) fs_exp_costs,\n    cast(ad.fc_exp_costs as decimal(11,2)) fc_exp_costs,\n    cast(ad.cb_exp_costs as decimal(11,2)) cb_exp_costs,\n    cast(ad.cc_exp_costs as decimal(11,2)) cc_exp_costs,\n    cast(ad.f2p_exp_costs as decimal(11,2)) f2p_exp_costs,\n    cast(ad.bb_exp_costs as decimal(11,2)) bb_exp_costs,\n    cast(ad.f1c_exp_costs as decimal(11,2)) f1c_exp_costs,\n    \n    cast(ad.Deposit_Amount as decimal(11,2)) Deposit_Amount,\n    cast(ad.Withdrawal_Amount as decimal(11,2)) Withdrawal_Amount, \n    cast(ad.Deposit_Count as int) Deposit_Count,\n    cast(ad.Withdrawal_Count as int) Withdrawal_Count,\n\n    cast(ad.f18m_pgp as decimal(11,2)) f18m_pgp,\n\n    cast(ad.tax as decimal(11,2)) tax,\n    cast(ad.content_fees as decimal(11,2)) content_fees,\n    cast(ad.market_access_fees as decimal(11,2)) market_access_fees,\n    cast(ad.payment_fees as decimal(11,2)) payment_fees,\n    cast(ad.geolocation_fees as decimal(11,2)) geolocation_fees,\n  \n    nvl(ActiveNextWeek,0) ActiveNextWeek, \n    nvl(ActiveNextMonth,0) ActiveNextMonth, \n    cast(w.cash_ggr_next_week as decimal(11,2)) cash_ggr_next_week,\n    cast(w.cash_eggr_next_week as decimal(11,2)) cash_eggr_next_week,\n    cast(m.cash_ggr_next_month as decimal(11,2)) cash_ggr_next_month,\n    cast(m.cash_eggr_next_month as decimal(11,2)) cash_eggr_next_month,\n\n    sysdate() as UpdateTimeUTC,\n    date(convert_timezone(\'UTC\',\'America/Anchorage\',sysdate())) current_date_alk\n    \nfrom AccountData ad\nleft join (\n  select \n    acco_id,\n    SK_Week,\n    max(case when nvl(APDs,0) > 0 then 1 else 0 end) ActiveNextWeek,\n    sum(cash_handle) cash_handle_next_week,\n    sum(cash_ggr) cash_ggr_next_week,\n    sum(cash_eggr) cash_eggr_next_week\n  from AccountData\n  group by 1,2\n) w \non ad.acco_id = w.acco_id and ad.SK_Week = dateadd(\'day\', -7, w.SK_Week)\nleft join (\n  select \n    acco_id,\n    SK_Month,\n    max(case when nvl(APDs,0) > 0 then 1 else 0 end) ActiveNextMonth,\n    sum(cash_handle) cash_handle_next_month,\n    sum(cash_ggr) cash_ggr_next_month,\n    sum(cash_eggr) cash_eggr_next_month\n  from AccountData\n  group by 1,2\n) m\non ad.acco_id = m.acco_id and ad.SK_Month = dateadd(\'month\', -1, m.SK_Month)\nwhere ad.SK_Week >= \'2023-11-13\' \n  and ad.SK_Date < date(convert_timezone(\'UTC\',\'America/Anchorage\',sysdate()))',NULL,'01c399ec-0212-67a9-24dd-0703192f9503','Thread-6 (worker)','table','{"_message": "SUCCESS 62375704", "code": "SUCCESS", "rows_affected": 62375704, "query_id": "01c399ec-0212-67a9-24dd-0703192f9503", "rows_inserted": 62375704, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('745e7718-e5c4-4d83-b60a-11215749b8ff.model.dbt_casino.reporting_rtc_promo_costs','model.dbt_casino.reporting_rtc_promo_costs','745e7718-e5c4-4d83-b60a-11215749b8ff','2026-04-09 21:13:29',
