,'reporting_rtc_promo_costs','SUCCESS 2770990','success','model',729.1702551841736,'2026-04-09T21:00:54.391372Z','2026-04-09T21:13:03.100863Z','2026-04-09T21:00:54.039759Z','2026-04-09T21:00:54.385810Z',2770990,False,'with bonuses as (\n    select\n        --a.acco_id,\n        c.casino_tier,\n        c.casino_value,\n        a.day as transaction_date,\n        -- a."Bonus Category" as bonus_category,\n        -- a."SubCategory" as subcategory,\n        -- a."Bonus Origin" as bonus_origin,\n        a."Bonus Code" as bonus_code,\n        -- a."Series" as series,\n        a.bonus_campaign_id,\n        coalesce(d.casino_vip,0) as casino_vip,\n        greatest(coalesce(d.casino_vip,0), coalesce(d.vip,0)) as fbg_vip,\n        coalesce(cast(c.casino_super_vip as int),0) as casino_super_vip,\n        --a.promo_type,\n        case \n        /* Test */\n             when a."SubCategory" = \'TEST\' then \'TEST\'\n        /* Acquisition and Early Life */\n             when a."Bonus Category" like \'%Acquisition\' and "Series" = \'Spin to Win\' then \'Fancash Spins Early Life\'\n             when a."Bonus Category" like \'%Acquisition\' and lower(a."Bonus Code") like \'%suo%\' then \'SUO\'\n             when a."Bonus Category" = \'CS Acquisition\' and lower(a."SubCategory") = \'raf\' then \'RaF - CS Adjustment\'\n             when a."Bonus Category" like \'%Acquisition\' and lower(a."SubCategory") = \'raf\' then \'RaF\'\n             when a."Bonus Category" like \'%Acquisition\' and lower(a."Bonus Code") like \'%^_ru^_%\' escape \'^\' then \'Rewards Unpacked\'\n             when a."Bonus Category" like \'%Acquisition\' then \'Other Acquisition\'\n        /* VIP */\n             when lower(a."Bonus Code") like \'%^_vcl^_%\' escape \'^\' then \'VIP Rebates\'\n             when lower(a."Bonus Code") like \'%goodwill%\' and lower(a."Bonus Code") like \'%vip%\' then \'VIP Rebates\'\n             when lower(a."Bonus Code") like \'%goodwill%\' and lower(a."Bonus Origin") like \'%vip%\' then \'VIP Rebates\'\n             when lower(a."Bonus Code") like \'%^_vcas^_lc^_churn^_%\' escape \'^\' then \'VIP Lifecycle Churn Risk\'\n             when lower(a."Bonus Code") like \'%^_vcas^_lc^_react^_%\' escape \'^\' then \'VIP Lifecycle Reactivation\'\n             when lower(a."Bonus Code") like \'%^_vcas^_ret^_rtc^_%\' escape \'^\' then \'VIP RTC Top Up\'\n             when lower(a."Bonus Code") like any (\'%vcas%\', \'%vipa%\') then \'VIP Promo\'\n             when lower(a."Bonus Code") like \'%vipsurvey%\' then \'VIP Survey\'\n        /* BAU & Overt */\n             when lower(a."Bonus Code") like \'%^_xsell^_%\' escape \'^\' and lower(a."Bonus Code") not like \'%^_lc^_%\' escape \'^\' then \'X-Sell\'\n             when lower(a."Bonus Code") like \'%^_overt^_%\' escape \'^\' then \'Overt Promos\'\n             when lower(a."Bonus Origin") = \'sweepstakes\' then \'Fancash Draws\'\n             when lower(a."Bonus Code") like \'%goodwill%\' then \'CS Adjustment\'\n             when a.bonus_campaign_id in (999997,999998) then \'CS Adjustment\' -- Casino cashback and CS Goodwill Appeasements\n             when lower(a."Bonus Code") like \'%^_cas^_ret^_%\' escape \'^\' and lower(a."Bonus Code") not like \'%rtc%\' then \'BAU Promos\'\n             when lower(a."Bonus Code") like any (\'%_bau_%\', \'%^_cas^_2m^_%\') escape \'^\' then \'BAU Promos\'\n             when a.bonus_campaign_id = 0 then \'Fancash Multipliers\' \n        /* Fanatics ONE */\n             when a."Bonus Code" = \'Fanatics One Credit\' then \'Fanatics ONE Credits\'\n             when lower(a."Bonus Code") like \'%vf1^_%\' escape \'^\' then \'Fanatics ONE Promos\'\n        /* Fancash */\n             when a."SubCategory" = \'FanCash Casino Base\' then \'FanCash Accrual\'\n             when transaction = \'fancash jackpot contribution\' then \'Fancash Jackpots\'\n        /* Fancash Spins (Retention) */\n             when "Series" = \'Spin to Win\' then \'Fancash Spins (excl. Early Life)\'\n        /* Lifecycle */\n             when lower(a."Bonus Code") like \'%^_cas^_lc^_churn^_%\' escape \'^\' then \'Lifecycle Churn Risk\'\n             when lower(a."Bonus Code") like \'%^_cas^_lc^_react^_%\' escape \'^\' then \'Lifecycle Reactivation\'\n             when lower(a."Bonus Code") like \'%^_cas^_lc^_%\' escape \'^\' then \'Lifecycle Other\'\n             when lower(a."Bonus Code") like \'%^_cas^_ret^_rtc^_%\' escape \'^\' then \'RTC Top Up\'\n             else null\n             end as promo_group_granular,\n        case when promo_group_granular in (\'Fancash Spins Early Life\', \'SUO\', \'RaF - CS Adjustment\', \'RaF\',\n                                           \'Rewards Unpacked\', \'Other Acquisition\') \n                    then \'Acquisition / Early Life\'\n             when promo_group_granular in (\'X-Sell\', \'Overt Promos\', \'Fancash Draws\', \'CS Adjustment\',\n                                           \'BAU Promos\', \'Fancash Multipliers\', \'VIP Promo\')\n                    then \'BAU & Overt\'\n             when promo_group_granular in (\'Fanatics ONE Credits\', \'Fanatics ONE Promos\')\n                    then \'Fanatics ONE\'\n             when promo_group_granular in (\'FanCash Accrual\', \'Fancash Jackpots\')\n                    then \'Fancash\'\n             when promo_group_granular in (\'Fancash Spins (excl. Early Life)\')\n                    then \'Fancash Spins (excl. Early Life)\'\n             when promo_group_granular in (\'Lifecycle Churn Risk\', \'Lifecycle Reactivation\', \'Lifecycle Other\', \'RTC Top Up\',\n                                           \'VIP Lifecycle Churn Risk\', \'VIP Lifecycle Reactivation\', \'VIP RTC Top Up\')\n                    then \'Lifecycle\'\n             when promo_group_granular in (\'VIP Rebates\', \'VIP Survey\')\n                    then \'VIP\'\n             end as promo_group,\n        sum(case when a.transaction in (\'bonus winnings\', \'fancash jackpot contribution\') then a.amount else 0 end) as cost,\n        sum(case when a.transaction in (\'bonus expected winnings\', \'fancash jackpot contribution\') then a.amount else 0 end) as expected_cost\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger a\n    left join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b on a.acco_id = b.acco_id\n    left join FBG_ANALYTICS.CASINO.casino_segments_historical c on a.acco_id = c.acco_id and date(a.date) = c.date\n    left join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.customer_account_history d on a.acco_id = d.acco_id and a.day between d.start_date and d.end_date\n    where a.transaction in (\'bonus winnings\', \'bonus expected winnings\', \'fancash jackpot contribution\')\n    and b.is_test_account = 0\n    and a.day is not null\n    group by all\n)\n\nselect\n    *,\n    sysdate() as UpdateTimeUTC\n from bonuses',NULL,'01c399ec-0212-644a-24dd-0703192fa4f3','Thread-12 (worker)','table','{"_message": "SUCCESS 2770990", "code": "SUCCESS", "rows_affected": 2770990, "query_id": "01c399ec-0212-644a-24dd-0703192fa4f3", "rows_inserted": 2770990, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}')
